do local player=game.Players.LocalPlayer;local character=player.Character or player.CharacterAdded:Wait() ;local rootPart=character:WaitForChild("HumanoidRootPart");local humanoid=character:WaitForChild("Humanoid");local screenGui=Instance.new("ScreenGui");screenGui.Parent=player:WaitForChild("PlayerGui");screenGui.Name="TradelandsHub";local frame=Instance.new("Frame");frame.Size=UDim2.new(0,380,0,420);frame.Position=UDim2.new(0.5, -190,0.5, -210);frame.BackgroundColor3=Color3.fromRGB(18,18,30);frame.BackgroundTransparency=0.1;frame.BorderSizePixel=0;frame.Parent=screenGui;frame.Active=true;frame.Draggable=true;local title=Instance.new("TextLabel");title.Size=UDim2.new(1,0,0,32);title.BackgroundTransparency=1;title.Text="✦ Tradelands Hub [Insert]";title.TextColor3=Color3.fromRGB(0,255,200);title.TextSize=16;title.Font=Enum.Font.GothamBold;title.Parent=frame;local scroll=Instance.new("ScrollingFrame");scroll.Size=UDim2.new(1, -10,1, -40);scroll.Position=UDim2.new(0,5,0,38);scroll.BackgroundTransparency=1;scroll.CanvasSize=UDim2.new(0,0,0,0);scroll.ScrollBarThickness=4;scroll.ScrollBarImageColor3=Color3.fromRGB(0,255,200);scroll.Parent=frame;local list=Instance.new("UIListLayout");list.Padding=UDim.new(0,5);list.SortOrder=Enum.SortOrder.LayoutOrder;list.Parent=scroll;local function toggle(text,default,cb) local btn=Instance.new("TextButton");btn.Size=UDim2.new(1,0,0,30);btn.BackgroundColor3=Color3.fromRGB(40,40,55);btn.BorderSizePixel=0;btn.Text=text   .. ": "   .. ((default and "ON") or "OFF") ;btn.TextColor3=Color3.fromRGB(210,210,225);btn.TextSize=13;btn.Font=Enum.Font.Gotham;btn.Parent=scroll;local state=default;btn.MouseButton1Click:Connect(function() state= not state;btn.Text=text   .. ": "   .. ((state and "ON") or "OFF") ;cb(state);end);cb(default);end local function button(text,cb) local btn=Instance.new("TextButton");btn.Size=UDim2.new(1,0,0,30);btn.BackgroundColor3=Color3.fromRGB(50,50,65);btn.BorderSizePixel=0;btn.Text=text;btn.TextColor3=Color3.fromRGB(21